-- ============================================
-- Legislacao full-site: ciro-gomes-gov-ce / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/141406
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = ciro-gomes-gov-ce-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 95 rows Camara legacy existentes, somente 42
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=141406, tipo Deputado(a), ordemAssinatura=1.
-- 53 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ciro-gomes-gov-ce';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ciro-gomes-gov-ce: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 95 THEN
    RAISE EXCEPTION 'Pre-condicao ciro-gomes-gov-ce: esperadas 95 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('474247', '474238', '474236', '474233', '463933', '463902', '397417', '382413', '382408', '361607', '353854', '433186', '418262', '397780', '397379', '382412', '382407', '353426', '397073', '385929', '382410', '361824', '359274', '418260', '397779', '391446', '382411', '367011', '359275', '396724', '382409', '361608', '474338', '424929', '400234', '463904', '456882', '428765', '428767', '409284', '421746', '463903');
  IF target_present <> 42 THEN
    RAISE EXCEPTION 'Pre-condicao ciro-gomes-gov-ce: esperadas 42 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('474247', '474238', '474236', '474233', '463933', '463902', '397417', '382413', '382408', '361607', '353854', '433186', '418262', '397780', '397379', '382412', '382407', '353426', '397073', '385929', '382410', '361824', '359274', '418260', '397779', '391446', '382411', '367011', '359275', '396724', '382409', '361608', '474338', '424929', '400234', '463904', '456882', '428765', '428767', '409284', '421746', '463903')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'ciro-gomes-gov-ce-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ciro-gomes-gov-ce: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ciro-gomes-gov-ce: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

